import React, { useState } from 'react'



import { CloseModal} 
from '../../../actions/common'
import { translatetext } from '../../../store/Util';


import {
  BTNH_Cmpt,
  Icon_Cmpt,
}  from  '../../components'



const BTNH = BTNH_Cmpt();
const Icon2 = Icon_Cmpt();






const UpdateInventoryModal = (props) => {
  const { data } = props;
  const {  modalID, item, userId  } = data;

  
  const remove = async () => {   
    if(typeof props.confirm === "function"){
      props.confirm();
    }
    CloseModal({id:modalID});
  }

  const reject = async () => {   
    if(typeof props.reject === "function"){
      props.reject();
    }
    CloseModal({id:modalID});
  }

  const clear = (v,f) => {
    CloseModal({id:modalID});
  }

 

  return (
    <div {...modalID?{"dialog-key-id":modalID}:""}  className={`pym81b sendBx upd_alert_bx modal_max_content`}>
      <style>
        {`
        .palette{
          --base-color: rgb(21, 100, 191,1);
          --base-color-gradient: 21, 100, 191;
        }
        `}
        </style>
        <div className={` _dsplFlx`}>
            <div  className={`delete_alert_t1 confAppnt`}>
            {`Confirmar cita para`}
            </div>
            <div className={`flexSpace`}/>  
            <div  className={`closeBtn`} onClick={clear} >
              <Icon2 
                name={"cancel"} 
                color={"#262626"}
              />
            </div>
        </div>
        <div className={`delete_alert_t2 confAppnt`}>
          <div>
            { userId}
          </div>
        </div>
        <div style={{ marginTop: "40px"}}></div>

        <div className={`sendBtn _dsplFlx spaceAround btnPos2Bottom`}>
          <div className={`fieldPadding _MrgV`} style={{ marginTop: "10px"}}>
            <span onClick={()=>reject()}>
              <BTNH theme={``} title={"Rechazar"} />
            </span>
          </div>
          <div className={`fieldPadding _MrgV`} style={{ marginTop: "10px"}}>
            <span onClick={()=>remove()}>
              <BTNH theme={`light_blue`} title={translatetext(78)}/>
            </span>
          </div>
        </div>
    </div>
    )
}


export default UpdateInventoryModal